#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int i[k];
        for (int j = 0; j < k; j++) {
            scanf("%d", &i[j]);
        }
        int p[n];
        int val = n;
        for (int j = k - 1; j >= 0; j--) {
            p[i[j] - 1] = val--;
        }
        for (int j = 0; j < n; j++) {
            if (p[j] == 0) {
                p[j] = val--;
            }
        }
        printf("YES\n");
        for (int j = 0; j < n; j++) {
            printf("%d ", p[j]);
        }
        printf("\n");
    }
    return 0;
}

