        while (T-- > 0) {
            int n = sc.nextInt();
            int k = sc.nextInt();
            int[] i = new int[k];
            for (int j = 0; j < k; j++) {
                i[j] = sc.nextInt();
            }
            int[] p = new int[n];
            int val = n;
            for (int j = k - 1; j >= 0; j--) {
                p[i[j] - 1] = val--;
            }
            for (int j = 0; j < n; j++) {
                if (p[j] == 0) {
                    p[j] = val--;
                }
            }
            System.out.println("YES");
            for (int j = 0; j < n; j++) {
